-- Enums
DO $$ BEGIN
  CREATE TYPE contract_status AS ENUM ('ativo', 'parcialmente_devolvido', 'encerrado');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE TYPE accessory_return_status AS ENUM ('ok', 'danificado', 'perdido', 'roubado');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- Tabela contracts
CREATE TABLE IF NOT EXISTS contracts (
  id SERIAL PRIMARY KEY,
  "clientId" INTEGER NOT NULL,
  status contract_status NOT NULL DEFAULT 'ativo',
  "valorTotal" NUMERIC(10,2),
  "pdfUrl" TEXT,
  "criadoEm" TIMESTAMP NOT NULL DEFAULT NOW(),
  "encerradoEm" TIMESTAMP,
  "deletedAt" TIMESTAMP
);

-- Tabela contract_accessories
CREATE TABLE IF NOT EXISTS contract_accessories (
  id SERIAL PRIMARY KEY,
  "contractId" INTEGER NOT NULL REFERENCES contracts(id) ON DELETE CASCADE,
  "accessoryId" INTEGER NOT NULL,
  qty INTEGER NOT NULL DEFAULT 1,
  status accessory_return_status NOT NULL DEFAULT 'ok',
  observacao TEXT,
  "fotoUrl" TEXT
);

-- Adicionar colunas à tabela rentals (se não existirem)
ALTER TABLE rentals ADD COLUMN IF NOT EXISTS "contractId" INTEGER REFERENCES contracts(id);
ALTER TABLE rentals ADD COLUMN IF NOT EXISTS "deletedAt" TIMESTAMP;

